exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <string>

class Sensor {
    std::string m_label{ "Unknown" };
    double m_temp{ 0.0 };

public:
    std::string& label()             { return m_label; }
    const std::string& label() const { return m_label; }
    double temp() const              { return m_temp; }
    void setTemp(double t)           { m_temp = t; }
};

int main() {
    std::string inputLabel{};
    double inputTemp{};
    std::cin >> inputLabel >> inputTemp;

    Sensor sensor{};
    sensor.label() = inputLabel;   // assign through mutable reference
    sensor.setTemp(inputTemp);

    const Sensor& cref = sensor;   // const reference -> calls const overload
    std::cout << "Label: " << cref.label() << "\n";
    std::cout << "Temp: " << std::fixed << std::setprecision(1) << sensor.temp() << "\n";

    return 0;
}

