exercises.solution_code:
#include <iostream>
#include <string>

class Player {
    std::string m_name{ "Anon" };
    int m_score{ 0 };

public:
    std::string& name()             { return m_name; }
    const std::string& name() const { return m_name; }
    int score() const               { return m_score; }
    void setScore(int s)            { m_score = s; }
};

int main() {
    int n{};
    std::cin >> n;

    Player players[10];

    for (int i = 0; i < n; ++i) {
        std::string readName{};
        int readScore{};
        std::cin >> readName >> readScore;
        players[i].name() = readName;   // assign through mutable reference
        players[i].setScore(readScore);
    }

    for (int i = 0; i < n; ++i) {
        const Player& p = players[i];
        std::cout << p.name() << ": " << p.score() << "\n";
    }

    int topIdx = 0;
    for (int i = 1; i < n; ++i) {
        const Player& p = players[i];
        if (p.score() > players[topIdx].score()) {
            topIdx = i;
        }
    }

    std::cout << "Top: " << players[topIdx].name() << "\n";

    return 0;
}
